from typing import List

class Solution:
    def maxOperations(self, nums: List[int]) -> int:
        if len(nums) < 2:
            return 0

        # Try all possible target sums derived from the first two elements
        possible_sums = set()
        possible_sums.add(nums[0] + nums[1])

        max_ops = 0
        for target_sum in possible_sums:
            current_sum = target_sum
            ops = 0
            i = 0
            while i + 1 < len(nums):
                if nums[i] + nums[i + 1] == current_sum:
                    ops += 1
                    i += 2
                else:
                    break
            max_ops = max(max_ops, ops)

        return max_ops
